// IPFS - Pure Rust CID computation (WASM-compatible)
use sha2::{Sha256, Digest};

/// Compute IPFS-compatible CIDv1 (raw codec + sha256) from string
pub fn ipfs_add(content: &str) -> Option<String> {
    ipfs_add_bytes(content.as_bytes())
}

/// Compute IPFS-compatible CIDv1 (raw codec + sha256) from bytes
pub fn ipfs_add_bytes(data: &[u8]) -> Option<String> {
    let hash = Sha256::digest(data);
    // CIDv1: version(1) + raw codec(0x55) + multihash(sha256=0x12, len=0x20, digest)
    let mut cid_bytes = vec![0x01, 0x55, 0x12, 0x20];
    cid_bytes.extend_from_slice(&hash);
    Some(format!("b{}", data_encoding::BASE32_NOPAD.encode(&cid_bytes).to_lowercase()))
}

