// IPFS - CID computation and content storage
use sha2::{Sha256, Digest};
use std::process::Command;
use std::io::Write;

/// Compute local CIDv1 (pure Rust, WASM-compatible) - for dedup only
pub fn local_cid(data: &[u8]) -> String {
    let hash = Sha256::digest(data);
    let mut cid_bytes = vec![0x01, 0x55, 0x12, 0x20];
    cid_bytes.extend_from_slice(&hash);
    format!("b{}", data_encoding::BASE32_NOPAD.encode(&cid_bytes).to_lowercase())
}

/// Add content to IPFS via CLI, returns real IPFS CID (Qm...)
pub fn ipfs_add(content: &str) -> Option<String> {
    ipfs_add_bytes(content.as_bytes())
}

/// Add bytes to IPFS via CLI, returns real IPFS CID
pub fn ipfs_add_bytes(data: &[u8]) -> Option<String> {
    let mut child = Command::new("ipfs")
        .args(&["add", "-Q", "--pin=false"])
        .stdin(std::process::Stdio::piped())
        .stdout(std::process::Stdio::piped())
        .stderr(std::process::Stdio::null())
        .spawn().ok()?;
    if let Some(mut stdin) = child.stdin.take() {
        stdin.write_all(data).ok()?;
    }
    let output = child.wait_with_output().ok()?;
    let cid = String::from_utf8(output.stdout).ok()?.trim().to_string();
    if cid.is_empty() { None } else { Some(cid) }
}

