// IPFS - Trait-based content addressing with pluggable backends
use sha2::{Sha256, Digest};

/// Content addressing backend trait
pub trait ContentStore: Send + Sync {
    fn name(&self) -> &str;
    fn add(&self, data: &[u8]) -> Option<String>;
    fn add_str(&self, content: &str) -> Option<String> { self.add(content.as_bytes()) }
}

/// Pure Rust DASL CID backend (no external deps, WASM-safe)
pub struct DaslStore;
impl ContentStore for DaslStore {
    fn name(&self) -> &str { "dasl" }
    fn add(&self, data: &[u8]) -> Option<String> {
        Some(crate::dasl::dasl_cid(data))
    }
}

/// IPFS CLI backend (shells out to `ipfs add`)
pub struct IpfsCliStore;
impl ContentStore for IpfsCliStore {
    fn name(&self) -> &str { "ipfs-cli" }
    fn add(&self, data: &[u8]) -> Option<String> {
        use std::process::Command;
        use std::io::Write;
        let mut child = Command::new("ipfs")
            .args(&["add", "-Q", "--pin=false"])
            .stdin(std::process::Stdio::piped())
            .stdout(std::process::Stdio::piped())
            .stderr(std::process::Stdio::null())
            .spawn().ok()?;
        if let Some(mut stdin) = child.stdin.take() { stdin.write_all(data).ok()?; }
        let out = child.wait_with_output().ok()?;
        let cid = String::from_utf8(out.stdout).ok()?.trim().to_string();
        if cid.is_empty() { None } else { Some(cid) }
    }
}

/// IPFS HTTP API backend (daemon at localhost:5001)
pub struct IpfsHttpStore { pub url: String }
impl IpfsHttpStore {
    pub fn new() -> Self { Self { url: "http://127.0.0.1:5001".into() } }
}
impl ContentStore for IpfsHttpStore {
    fn name(&self) -> &str { "ipfs-http" }
    fn add(&self, data: &[u8]) -> Option<String> {
        let client = reqwest::blocking::Client::builder()
            .timeout(std::time::Duration::from_secs(5)).build().ok()?;
        let form = reqwest::blocking::multipart::Form::new()
            .part("file", reqwest::blocking::multipart::Part::bytes(data.to_vec()).file_name("data"));
        let resp = client.post(format!("{}/api/v0/add?pin=false&quiet=true", self.url))
            .multipart(form).send().ok()?;
        let json: serde_json::Value = resp.json().ok()?;
        json["Hash"].as_str().map(|s| s.to_string())
    }
}

/// Multi-backend store: tries each backend in order, returns first success
pub struct MultiStore {
    backends: Vec<Box<dyn ContentStore>>,
}

impl MultiStore {
    pub fn new(backends: Vec<Box<dyn ContentStore>>) -> Self { Self { backends } }
}

impl ContentStore for MultiStore {
    fn name(&self) -> &str { "multi" }
    fn add(&self, data: &[u8]) -> Option<String> {
        for b in &self.backends {
            if let Some(cid) = b.add(data) {
                log::info!("📦 CID via {}: {}", b.name(), cid);
                return Some(cid);
            }
        }
        None
    }
}

// === Convenience functions (use default DASL backend) ===

pub fn ipfs_add(content: &str) -> Option<String> {
    ipfs_add_bytes(content.as_bytes())
