// === Convenience: compute CID + write block to IPFS flatfs repo ===

pub fn ipfs_add(content: &str) -> Option<String> {
    ipfs_add_bytes(content.as_bytes())
}

pub fn ipfs_add_bytes(data: &[u8]) -> Option<String> {
    // Build the dag-pb block (same as ipfs add)
    let unixfs = encode_unixfs(data);
    let block = encode_dagpb(&unixfs);

    // SHA256 the block
    let hash = Sha256::digest(&block);

    // Multihash: 0x12 (sha256) + 0x20 (32 bytes) + digest
    let mut mh = vec![0x12, 0x20];
    mh.extend_from_slice(&hash);

    // CIDv1 for return: version(1) + dag-pb(0x70) + multihash
    let mut cidv1 = vec![0x01, 0x70];
    cidv1.extend_from_slice(&mh);
    let cid_str = format!("b{}", data_encoding::BASE32_NOPAD.encode(&cidv1).to_lowercase());

    // Write block to IPFS flatfs repo
    // Key format: base32upper(multihash) with CID prefix
    // Flatfs: ~/.ipfs/blocks/XX/KEY.data where XX = next-to-last 2 chars
    let ipfs_path = dirs();
    if let Some(repo) = ipfs_path {
        let key = data_encoding::BASE32_NOPAD.encode(&mh);
        // next-to-last/2 sharding
        let shard = if key.len() >= 4 {
            &key[key.len()-3..key.len()-1]
        } else {
            "AA"
        };
        let block_dir = format!("{}/blocks/{}", repo, shard);
        std::fs::create_dir_all(&block_dir).ok();
        let block_path = format!("{}/{}.data", block_dir, key);
        std::fs::write(&block_path, &block).ok();
        log::info!("📦 IPFS block written: {}", block_path);
    }

    Some(cid_str)
}

/// Read content from IPFS flatfs repo by CID
pub fn ipfs_cat(cid: &str) -> Option<Vec<u8>> {
    let repo = dirs()?;
    // Decode CIDv1: strip multibase prefix 'b', base32 decode, skip version+codec, get multihash
    let cid_trimmed = cid.strip_prefix('b')?;
    let cid_bytes = data_encoding::BASE32_NOPAD.decode(cid_trimmed.to_uppercase().as_bytes()).ok()?;
    // Skip version (1 byte) + codec varint (1-2 bytes for 0x70)
    let mh_start = if cid_bytes.len() > 2 && cid_bytes[0] == 0x01 { 2 } else { 0 };
    let mh = &cid_bytes[mh_start..];
    let key = data_encoding::BASE32_NOPAD.encode(mh);
    let shard = if key.len() >= 4 { &key[key.len()-3..key.len()-1] } else { "AA" };
    let block_path = format!("{}/blocks/{}/{}.data", repo, shard, key);
    std::fs::read(&block_path).ok()
}

fn dirs() -> Option<String> {
    // Check IPFS_PATH env, then default ~/.ipfs
    std::env::var("IPFS_PATH").ok().or_else(|| {
        dirs_next::home_dir().map(|h| format!("{}/.ipfs", h.display()))
    }).filter(|p| std::path::Path::new(p).exists())
}

pub fn local_cid(data: &[u8]) -> String {
    let hash = Sha256::digest(data);
    format!("bafk{}", hex::encode(&hash[..16]))
}

